    const word_t s4_seq = cell_dff(r[FIFO_FIFO_SLOT_4_SEQ], rd_seq, (cell_eqmask(wr_idx, 4ULL) & wr_fire));
    const word_t s5_bid_px = cell_dff(r[FIFO_FIFO_SLOT_5_BID_PX], rd_bid_px, (cell_eqmask(wr_idx, 5ULL) & wr_fire));
    const word_t s5_ask_px = cell_dff(r[FIFO_FIFO_SLOT_5_ASK_PX], rd_ask_px, (cell_eqmask(wr_idx, 5ULL) & wr_fire));
    const word_t s5_time = cell_dff(r[FIFO_FIFO_SLOT_5_TIME], rd_time, (cell_eqmask(wr_idx, 5ULL) & wr_fire));
    const word_t s5_src_time = cell_dff(r[FIFO_FIFO_SLOT_5_SRC_TIME], rd_src_time, (cell_eqmask(wr_idx, 5ULL) & wr_fire));
