/* fifo_rx_head_addr: the register address of lane `lane_ofs` in the slot
 * at the READ pointer (rd_bin & mask). Address math only (no data path). */
static inline word_t fifo_rx_head_addr(const word_t *r, word_t lane_ofs) {
    const word_t rd_idx = cell_and(r[FIFO_FIFO_RD_BIN], FIFO_SLOT_MASK);
    const word_t slot0 = (word_t)FIFO_FIFO_SLOT_0_BID_PX;
    return slot0 + rd_idx * 8ULL + lane_ofs;
}

/* fifo_rx_run: the canonical clock primitive. The FIFO self-runs on its
 * clock edge while powered, bounded by a configured tick budget (config,
 * not external stepping). The starter powers it on and steps away. */
static inline void fifo_rx_run(word_t *r, const word_t *nic) {
    while ((r[FIFO_FIFO_POWER] & 1ULL)
           && fifo_cmp_lt(r[FIFO_FIFO_TICKS], r[FIFO_FIFO_RUN_UNTIL])) {
        fifo_rx_tick(r, nic);
        r[FIFO_FIFO_TICKS] = cell_addsub(r[FIFO_FIFO_TICKS], 1ULL, 0ULL);
    }
}

